<script setup lang="ts">
import {computed,ref,onMounted,watch} from 'vue';import {ElMessage} from 'element-plus';import {api} from '../../api';import {useMerchantContext} from '../../stores/merchantContext';
const c=useMerchantContext();const merchantId=computed(()=>c.merchant.value?.id);const stores=ref<any[]>([]),platform=ref('XIAOHONGSHU'),profiles=ref<any[]>([]),gaps=ref<any[]>([]),fields=ref<any[]>([]),selected=ref<any>(null),showProfile=ref(false),showField=ref(false);const form=ref<any>({accountName:'',profileUrl:'',profileScope:'BRAND'}),field=ref<any>({fieldKey:'BRAND_NAME',value:'',status:'UNVERIFIED',sourceType:'MANUAL_ENTRY'});const names:any={XIAOHONGSHU:'小红书',DIANPING:'大众点评',AMAP:'高德地图'};const keys=['BRAND_NAME','STORE_NAME','ADDRESS','PHONE','BUSINESS_HOURS','SERVICE_ITEM','PRICE_RANGE'];
async function load(){if(!merchantId.value)return;stores.value=(await api('/merchants/'+merchantId.value+'/fact-center/summary')).storefronts||[];profiles.value=await api(`/merchants/${merchantId.value}/platform-assets`);selected.value=profiles.value.find(x=>x.platform===platform.value)||null;gaps.value=await api(`/merchants/${merchantId.value}/platform-assets/gaps`);if(selected.value)fields.value=await api(`/merchants/${merchantId.value}/platform-assets/${selected.value.id}/fields`);else fields.value=[]}
async function saveProfile(){const scope=platform.value==='XIAOHONGSHU'?form.value.profileScope:'STOREFRONT';let store:any=null;if(scope==='STOREFRONT')store=stores.value.find((x:any)=>x.isPrimary)?.id;if(scope==='STOREFRONT'&&!store){ElMessage.error('请先在商家事实中创建主门店');return}await api(`/merchants/${merchantId.value}/platform-assets`,{method:'POST',body:JSON.stringify({...form.value,platform:platform.value,profileScope:scope,storefrontId:store})});showProfile.value=false;await load();}
async function saveField(){if(!selected.value)return;await api(`/merchants/${merchantId.value}/platform-assets/${selected.value.id}/fields`,{method:'POST',body:JSON.stringify(field.value)});showField.value=false;await load()}
async function compare(){if(!selected.value)return;await api(`/merchants/${merchantId.value}/platform-assets/${selected.value.id}/compare`,{method:'POST'});await load();ElMessage.success('资料比较完成')}
async function task(g:any){const r=await api(`/merchants/${merchantId.value}/platform-asset-gaps/${g.id}/create-task`,{method:'POST'});ElMessage.success(`已生成任务：${r.title}`);await c.refresh();await load()}
async function status(g:any,s:string){await api(`/merchants/${merchantId.value}/platform-assets/gaps/${g.id}`,{method:'PATCH',body:JSON.stringify({status:s})});await load()}
watch(platform,load);onMounted(load);
</script>
<template><section class="module-page platform-assets"><div class="module-heading"><div><span class="eyebrow">PLATFORM ASSETS</span><h2>平台资产</h2><p>人工录入并核验商家公开资料，与事实中心进行对照。</p></div><el-button type="primary" :disabled="!selected" @click="compare">运行资料比较</el-button></div><el-alert title="当前版本仅支持人工录入和人工核验，不会自动抓取平台资料。" type="info" :closable="false"/><el-tabs v-model="platform"><el-tab-pane v-for="(_,key) in names" :key="key" :name="key" :label="names[key]"/></el-tabs><div class="metrics"><div><b>{{fields.length}}</b><span>资料字段</span></div><div><b>{{gaps.filter(x=>x.status==='OPEN'&&x.platform_profile_id===selected?.id).length}}</b><span>OPEN Gap</span></div><div><b>{{fields.filter(x=>x.status!=='VERIFIED').length}}</b><span>待核验字段</span></div></div><div class="panel"><div class="row-title"><h3>平台档案</h3><el-button size="small" @click="showProfile=true">新建档案</el-button></div><template v-if="selected"><b>{{selected.account_name||'未命名档案'}}</b><p><a :href="selected.profile_url" target="_blank">{{selected.profile_url||'未填写链接'}}</a></p><small>{{selected.profile_scope}} · {{selected.verification_status}} · 观察 {{selected.last_observed_at||'未记录'}}</small></template><p v-else>当前平台尚无档案，请人工创建。</p></div><div class="panel"><div class="row-title"><h3>字段对照</h3><el-button size="small" :disabled="!selected" @click="showField=true">新增字段版本</el-button></div><el-table :data="fields" size="small"><el-table-column prop="field_key" label="字段"/><el-table-column prop="normalized_text" label="平台当前值"/><el-table-column prop="status" label="核验状态"/><el-table-column prop="source_type" label="来源"/><el-table-column prop="created_at" label="更新时间"/></el-table></div><div class="panel"><h3>Gap 面板</h3><el-table :data="gaps.filter(x=>x.platform_profile_id===selected?.id)" size="small"><el-table-column prop="gap_type" label="类型"/><el-table-column prop="field_key" label="字段"/><el-table-column prop="priority" label="优先级"/><el-table-column prop="difference_summary" label="差异说明"/><el-table-column label="操作" width="250"><template #default="{row}"><el-button size="small" :disabled="row.generated_task_id" @click="task(row)">{{row.generated_task_id?'已生成任务':'生成整改任务'}}</el-button><el-button size="small" @click="status(row,'RESOLVED')">解决</el-button><el-button size="small" @click="status(row,'IGNORED')">忽略</el-button></template></el-table-column></el-table></div><el-dialog v-model="showProfile" title="新建平台档案"><el-input v-model="form.accountName" placeholder="账号或门店名称"/><el-input v-model="form.profileUrl" placeholder="资料链接"/><el-select v-if="platform==='XIAOHONGSHU'" v-model="form.profileScope"><el-option label="品牌" value="BRAND"/><el-option label="门店" value="STOREFRONT"/></el-select><template #footer><el-button @click="showProfile=false">取消</el-button><el-button type="primary" @click="saveProfile">保存</el-button></template></el-dialog><el-dialog v-model="showField" title="新增平台字段版本"><el-select v-model="field.fieldKey"><el-option v-for="x in keys" :key="x" :label="x" :value="x"/></el-select><el-input v-model="field.value" placeholder="平台当前值"/><el-select v-model="field.status"><el-option label="未核验" value="UNVERIFIED"/><el-option label="已核验" value="VERIFIED"/></el-select><template #footer><el-button @click="showField=false">取消</el-button><el-button type="primary" @click="saveField">保存</el-button></template></el-dialog></section></template>
<style scoped>.platform-assets{max-width:1440px}.metrics{display:flex;gap:12px;margin:16px 0}.metrics div,.panel{background:#fff;border:1px solid #dce7df;border-radius:12px;padding:16px}.metrics div{min-width:130px;display:flex;flex-direction:column}.metrics b{font-size:26px;color:#176d42}.metrics span,small{color:#718078}.panel{margin:14px 0}.row-title{display:flex;justify-content:space-between;align-items:center}.row-title h3{margin:0 0 10px}a{color:#23774b;word-break:break-all}</style>
